parameters.jsCode:
try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    const business = $node['Split In Batches'].json;
    let script;
    try {
      const text = item.json.content[0].text;
      script = JSON.parse(text);
    } catch(e) {
      const text = item.json.content[0].text;
      const match = text.match(/\{[\s\S]*\}/);
      script = match ? JSON.parse(match[0]) : {hook:'', full_script:'', camera_directions:[], caption:'', hashtags:[]};
    }
    results.push({json: {
      business_id: business.id,
      business_name: business.business_name || '',
      email: business.email || '',
      hook: script.hook || '',
      full_script: script.full_script || '',
      camera_directions: script.camera_directions || [],
      caption: script.caption || '',
      hashtags: script.hashtags || [],
      estimated_duration: script.estimated_duration_seconds || 60,
      call_to_action: script.call_to_action || '',
      content_theme: 'video_script',
      status: 'pending_approval',
      created_at: new Date().toISOString()
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message}}];
}
